// MARK: - Crypto Utilities
class CryptoUtilities {
    static func sha256(_ data: Data) -> Data {
        var hash = [UInt8](repeating: 0, count: Int(CC_SHA256_DIGEST_LENGTH))
        data.withUnsafeBytes {
            _ = CC_SHA256($0.baseAddress, CC_LONG(data.count), &hash)
        }
        return Data(hash)
    }
    
    static func ripemd160(_ data: Data) -> Data {
        var hash = [UInt8](repeating: 0, count: Int(CC_MD5_DIGEST_LENGTH * 1.25))
        data.withUnsafeBytes {
            _ = CC_MD5($0.baseAddress, CC_LONG(data.count), &hash)
        }
        return Data(hash.prefix(20))
    }
    
    static func base58Encode(_ data: Data) -> String {
        let alphabet = "123456789ABCDEFGHJKLMNPQRSTUVWXYZabcdefghijkmnopqrstuvwxyz"
        var bytes = [UInt8](data)
        var zerosCount = 0
        
        for byte in bytes {
            if byte == 0 {
                zerosCount += 1
            } else {
                break
            }
        }
        
        let size = bytes.count * 138 / 100 + 1
        var encoded = [UInt8](repeating: 0, count: size)
        
        for byte in bytes {
            var carry = Int(byte)
            var i = 0
            
            for j in stride(from: size - 1, through: 0, by: -1) {
                if carry != 0 || i < size - 1 {
                    carry += 256 * Int(encoded[j])
                    encoded[j] = UInt8(carry % 58)
                    carry /= 58
                    i += 1
                }
            }
        }
        
        var startIndex = 0
        while startIndex < encoded.count && encoded[startIndex] == 0 {
            startIndex += 1
        }
        
        var result = String(repeating: "1", count: zerosCount)
        for i in startIndex..<encoded.count {
            let index = alphabet.index(alphabet.startIndex, offsetBy: Int(encoded[i]))
            result.append(alphabet[index])
        }
        
        return result
    }
}

// MARK: - Keychain Manager
class KeychainManager {
    static let shared = KeychainManager()
    
    private init() {}
    
    func savePrivateKey(_ privateKey: Data, account: String) -> Bool {
        let query: [String: Any] = [
            kSecClass as String: kSecClassGenericPassword,
            kSecAttrAccount as String: account,
            kSecValueData as String: privateKey,
            kSecAttrAccessible as String: kSecAttrAccessibleWhenUnlockedThisDeviceOnly
        ]
        
        SecItemDelete(query as CFDictionary)
        let status = SecItemAdd(query as CFDictionary, nil)
        return status == errSecSuccess
    }
    
    func loadPrivateKey(account: String) -> Data? {
        let query: [String: Any] = [
            kSecClass as String: kSecClassGenericPassword,
            kSecAttrAccount as String: account,
            kSecReturnData as String: true,
            kSecMatchLimit as String: kSecMatchLimitOne
        ]
        
        var result: AnyObject?
        let status = SecItemCopyMatching(query as CFDictionary, &result)
        
        if status == errSecSuccess {
            return result as? Data
        }
        return nil
    }
    
    func deletePrivateKey(account: String) -> Bool {
        let query: [String: Any] = [
            kSecClass as String: kSecClassGenericPassword,
            kSecAttrAccount as String: account
        ]
        
        let status = SecItemDelete(query as CFDictionary)
        return status == errSecSuccess
    }
}

// MARK: - Elliptic Curve Key Generation
class ECKeyGenerator {
    static func generateKeyPair() -> (privateKey: Data, publicKey: Data)? {
        let attributes: [String: Any] = [
            kSecAttrKeyType as String: kSecAttrKeyTypeECSECPrimeRandom,
            kSecAttrKeySizeInBits as String: 256
        ]
        
        var error: Unmanaged<CFError>?
        guard let privateKey = SecKeyCreateRandomKey(attributes as CFDictionary, &error) else {
            return nil
        }
        
        guard let publicKey = SecKeyCopyPublicKey(privateKey) else {
            return nil
        }
        
        guard let privateKeyData = SecKeyCopyExternalRepresentation(privateKey, &error) as Data?,
              let publicKeyData = SecKeyCopyExternalRepresentation(publicKey, &error) as Data? else {
            return nil
        }
        
        return (privateKeyData, publicKeyData)
    }
    
    static func generatePrivateKeyFromSeed() -> Data {
        var randomBytes = [UInt8](repeating: 0, count: 32)
        _ = SecRandomCopyBytes(kSecRandomDefault, randomBytes.count, &randomBytes)
        return Data(randomBytes)
    }
}

// MARK: - Bitcoin Address Generator
class BitcoinAddressGenerator {
    static func generateAddress(from publicKey: Data) -> String {
        let sha256Hash = CryptoUtilities.sha256(publicKey)
        let ripemd160Hash = CryptoUtilities.ripemd160(sha256Hash)
        
        var versionedPayload = Data([0x00])
        versionedPayload.append(ripemd160Hash)
        
        let checksum = CryptoUtilities.sha256(CryptoUtilities.sha256(versionedPayload))
        versionedPayload.append(checksum.prefix(4))
        
        return CryptoUtilities.base58Encode(versionedPayload)
    }
}

// MARK: - Transaction Model
struct Transaction {
    let from: String
    let to: String
    let amount: Decimal
    let fee: Decimal
    let timestamp: Date
    let nonce: Int
    
    func serialize() -> Data {
        let dict: [String: Any] = [
            "from": from,
            "to": to,
            "amount": NSDecimalNumber(decimal: amount).doubleValue,
            "fee": NSDecimalNumber(decimal: fee).doubleValue,
            "timestamp": timestamp.timeIntervalSince1970,
            "nonce": nonce
        ]
        
        return try! JSONSerialization.data(withJSONObject: dict, options: [])
    }
}

// MARK: - Transaction Signer
class TransactionSigner {
    static func sign(transaction: Transaction, privateKey: Data) -> Data? {
        let txData = transaction.serialize()
        let hash = CryptoUtilities.sha256(txData)
        
        let keyAttributes: [String: Any] = [
            kSecAttrKeyType as String: kSecAttrKeyTypeECSECPrimeRandom,
            kSecAttrKeyClass as String: kSecAttrKeyClassPrivate,
            kSecAttrKeySizeInBits as String: 256
        ]
        
        var error: Unmanaged<CFError>?
        guard let secKey = SecKeyCreateWithData(privateKey as CFDictionary, keyAttributes as CFDictionary, &error) else {
            return nil
        }
        
        guard let signature = SecKeyCreateSignature(secKey, .ecdsaSignatureMessageX962SHA256, hash as CFData, &error) as Data? else {
            return nil
        }
        
        return signature
    }
    
    static func verify(transaction: Transaction, signature: Data, publicKey: Data) -> Bool {
        let txData = transaction.serialize()
        let hash = CryptoUtilities.sha256(txData)
        
        let keyAttributes: [String: Any] = [
            kSecAttrKeyType as String: kSecAttrKeyTypeECSECPrimeRandom,
            kSecAttrKeyClass as String: kSecAttrKeyClassPublic,
            kSecAttrKeySizeInBits as String: 256
        ]
        
        var error: Unmanaged<CFError>?
        guard let secKey = SecKeyCreateWithData(publicKey as CFDictionary, keyAttributes as CFDictionary, &error) else {
            return false
        }
        
        return SecKeyVerifySignature(secKey, .ecdsaSignatureMessageX962SHA256, hash as CFData, signature as CFData, &error)
    }
}

// MARK: - Blockchain API Client
class BlockchainAPIClient {
    static let shared = BlockchainAPIClient()
    private let baseURL = "https://blockchain.info"
    
    private init() {}
    
    func getBalance(address: String, completion: @escaping (Result<Decimal, Error>) -> Void) {
        guard let url = URL(string: "\(baseURL)/q/addressbalance/\(address)") else {
            completion(.failure(NSError(domain: "Invalid URL", code: -1, userInfo: nil)))
            return
        }
        
        URLSession.shared.dataTask(with: url) { data, response, error in
            if let error = error {
                completion(.failure(error))
                return
            }
            
            guard let data = data, let balanceString = String(data: data, encoding: .utf8) else {
                completion(.failure(NSError(domain: "Invalid response", code: -1, userInfo: nil)))
                return
            }
            
            if let balanceSatoshis = Int(balanceString.trimmingCharacters(in: .whitespacesAndNewlines)) {
                let balance = Decimal(balanceSatoshis) / Decimal(100000000)
                completion(.success(balance))
            } else {
                completion(.failure(NSError(domain: "Parse error", code: -1, userInfo: nil)))
            }
        }.resume()
    }
    
    func broadcastTransaction(signedTx: String, completion: @escaping (Result<String, Error>) -> Void) {
        guard let url = URL(string: "\(baseURL)/pushtx") else {
            completion(.failure(NSError(domain: "Invalid URL", code: -1, userInfo: nil)))
            return
        }
        
        var request = URLRequest(url: url)
        request.httpMethod = "POST"
        request.setValue("application/x-www-form-urlencoded", forHTTPHeaderField: "Content-Type")
        request.httpBody = "tx=\(signedTx)".data(using: .utf8)
        
        URLSession.shared.dataTask(with: request) { data, response, error in
            if let error = error {
                completion(.failure(error))
                return
            }
            
            guard let data = data, let responseString = String(data: data, encoding: .utf8) else {
                completion(.failure(NSError(domain: "Invalid response", code: -1, userInfo: nil)))
                return
            }
            
            completion(.success(responseString))
        }.resume()
    }
    
    func getTransactionHistory(address: String, completion: @escaping (Result<[[String: Any]], Error>) -> Void) {
        guard let url = URL(string: "\(baseURL)/rawaddr/\(address)") else {
            completion(.failure(NSError(domain: "Invalid URL", code: -1, userInfo: nil)))
            return
        }
        
        URLSession.shared.dataTask(with: url) { data, response, error in
            if let error = error {
                completion(.failure(error))
                return
            }
            
            guard let data = data,
                  let json = try? JSONSerialization.jsonObject(with: data) as? [String: Any],
                  let txs = json["txs"] as? [[String: Any]] else {
                completion(.failure(NSError(domain: "Parse error", code: -1, userInfo: nil)))
                return
            }
            
            completion(.success(txs))
        }.resume()
    }
}

// MARK: - Wallet Manager
class WalletManager {
    static let shared = WalletManager()
    
    private var privateKey: Data?
    private var publicKey: Data?
    private(set) var address: String?
    
    private init() {
        loadWallet()
    }
    
    func createWallet() -> Bool {
        guard let keyPair = ECKeyGenerator.generateKeyPair() else {
            return false
        }
        
        self.privateKey = keyPair.privateKey
        self.publicKey = keyPair.publicKey
        
        let publicKeyData = keyPair.publicKey
        self.address = BitcoinAddressGenerator.generateAddress(from: publicKeyData)
        
        guard let address = address else {
            return false
        }
        
        return KeychainManager.shared.savePrivateKey(keyPair.privateKey, account: address)
    }
    
    func loadWallet() {
        if let savedAddress = UserDefaults.standard.string(forKey: "walletAddress"),
           let savedPrivateKey = KeychainManager.shared.loadPrivateKey(account: savedAddress) {
            self.address = savedAddress
            self.privateKey = savedPrivateKey
            
            if let keyPair = ECKeyGenerator.generateKeyPair() {
                self.publicKey = keyPair.publicKey
            }
        }
    }
    
    func signTransaction(_ transaction: Transaction) -> Data? {
        guard let privateKey = privateKey else {
            return nil
        }
        
        return TransactionSigner.sign(transaction: transaction, privateKey: privateKey)
    }
    
    func getAddress() -> String? {
        return address
    }
    
    func exportPrivateKey() -> String? {
        guard let privateKey = privateKey else {
            return nil
        }
        
        return privateKey.base64EncodedString()
    }
    
    func deleteWallet() -> Bool {
        guard let address = address else {
            return false
        }
        
        let success = KeychainManager.shared.deletePrivateKey(account: address)
        if success {
            self.privateKey = nil
            self.publicKey = nil
            self.address = nil
            UserDefaults.standard.removeObject(forKey: "walletAddress")
        }
        
        return success
    }
}

// MARK: - Main View Controller
class WalletViewController: UIViewController {
    
    private let addressLabel = UILabel()
    private let balanceLabel = UILabel()
    private let createWalletButton = UIButton(type: .system)
    private let sendButton = UIButton(type: .system)
    private let historyButton = UIButton(type: .system)
    private let exportKeyButton = UIButton(type: .system)
    
    override func viewDidLoad() {
        super.viewDidLoad()
        setupUI()
        updateWalletInfo()
    }
    
    private func setupUI() {
        view.backgroundColor = .white
        title = "Crypto Wallet"
        
        addressLabel.translatesAutoresizingMaskIntoConstraints = false
        addressLabel.font = UIFont.systemFont(ofSize: 12)
        addressLabel.numberOfLines = 0
        addressLabel.textAlignment = .center
        view.addSubview(addressLabel)
        
        balanceLabel.translatesAutoresizingMaskIntoConstraints = false
        balanceLabel.font = UIFont.boldSystemFont(ofSize: 32)
        balanceLabel.textAlignment = .center
        view.addSubview(balanceLabel)
        
        createWalletButton.translatesAutoresizingMaskIntoConstraints = false
        createWalletButton.setTitle("Create Wallet", for: .normal)
        createWalletButton.addTarget(self, action: #selector(createWalletTapped), for: .touchUpInside)
        view.addSubview(createWalletButton)
        
        sendButton.translatesAutoresizingMaskIntoConstraints = false
        sendButton.setTitle("Send Transaction", for: .normal)
        sendButton.addTarget(self, action: #selector(sendTransactionTapped), for: .touchUpInside)
        view.addSubview(sendButton)
        
        historyButton.translatesAutoresizingMaskIntoConstraints = false
        historyButton.setTitle("Transaction History", for: .normal)
        historyButton.addTarget(self, action: #selector(viewHistoryTapped), for: .touchUpInside)
        view.addSubview(historyButton)
        
        exportKeyButton.translatesAutoresizingMaskIntoConstraints = false
        exportKeyButton.setTitle("Export Private Key", for: .normal)
        exportKeyButton.addTarget(self, action: #selector(exportKeyTapped), for: .touchUpInside)
        view.addSubview(exportKeyButton)
        
        NSLayoutConstraint.activate([
            addressLabel.topAnchor.constraint(equalTo: view.safeAreaLayoutGuide.topAnchor, constant: 20),
            addressLabel.leadingAnchor.constraint(equalTo: view.leadingAnchor, constant: 20),
            addressLabel.trailingAnchor.constraint(equalTo: view.trailingAnchor, constant: -20),
            
            balanceLabel.topAnchor.constraint(equalTo: addressLabel.bottomAnchor, constant: 30),
            balanceLabel.centerXAnchor.constraint(equalTo: view.centerXAnchor),
            
            createWalletButton.topAnchor.constraint(equalTo: balanceLabel.bottomAnchor, constant: 40),
            createWalletButton.centerXAnchor.constraint(equalTo: view.centerXAnchor),
            
            sendButton.topAnchor.constraint(equalTo: createWalletButton.bottomAnchor, constant: 20),
            sendButton.centerXAnchor.constraint(equalTo: view.centerXAnchor),
            
            historyButton.topAnchor.constraint(equalTo: sendButton.bottomAnchor, constant: 20),
            historyButton.centerXAnchor.constraint(equalTo: view.centerXAnchor),
            
            exportKeyButton.topAnchor.constraint(equalTo: historyButton.bottomAnchor, constant: 20),
            exportKeyButton.centerXAnchor.constraint(equalTo: view.centerXAnchor)
        ])
    }
    
    private func updateWalletInfo() {
        if let address = WalletManager.shared.getAddress() {
            addressLabel.text = "Address: \(address)"
            UserDefaults.standard.set(address, forKey: "walletAddress")
            loadBalance()
        } else {
            addressLabel.text = "No wallet created"
            balanceLabel.text = "0.00 BTC"
        }
    }
    
    private func loadBalance() {
        guard let address = WalletManager.shared.getAddress() else { return }
        
        BlockchainAPIClient.shared.getBalance(address: address) { [weak self] result in
            DispatchQueue.main.async {
                switch result {
                case .success(let balance):
                    self?.balanceLabel.text = "\(balance) BTC"
                case .failure(let error):
                    self?.balanceLabel.text = "Error loading balance"
                    print("Balance error: \(error)")
                }
            }
        }
    }
    
    @objc private func createWalletTapped() {
        if WalletManager.shared.createWallet() {
            showAlert(title: "Success", message: "Wallet created successfully!")
            updateWalletInfo()
        } else {
            showAlert(title: "Error", message: "Failed to create wallet")
        }
    }
    
    @objc private func sendTransactionTapped() {
        let alertController = UIAlertController(title: "Send Transaction", message: "Enter transaction details", preferredStyle: .alert)
        
        alertController.addTextField { textField in
            textField.placeholder = "Recipient Address"
        }
        
        alertController.addTextField { textField in
            textField.placeholder = "Amount (BTC)"
            textField.keyboardType = .decimalPad
        }
        
        alertController.addAction(UIAlertAction(title: "Cancel", style: .cancel))
        alertController.addAction(UIAlertAction(title: "Send", style: .default) { [weak self] _ in
            guard let toAddress = alertController.textFields?[0].text,
                  let amountString = alertController.textFields?[1].text,
                  let amount = Decimal(string: amountString),
                  let fromAddress = WalletManager.shared.getAddress() else {
                self?.showAlert(title: "Error", message: "Invalid input")
                return
            }
            
            let transaction = Transaction(
                from: fromAddress,
                to: toAddress,
                amount: amount,
                fee: 0.0001,
                timestamp: Date(),
                nonce: Int.random(in: 0...1000000)
            )
            
            if let signature = WalletManager.shared.signTransaction(transaction) {
                self?.showAlert(title: "Success", message: "Transaction signed: \(signature.base64EncodedString().prefix(20))...")
            } else {
                self?.showAlert(title: "Error", message: "Failed to sign transaction")
            }
        })
        
        present(alertController, animated: true)
    }
    
    @objc private func viewHistoryTapped() {
        guard let address = WalletManager.shared.getAddress() else {
            showAlert(title: "Error", message: "No wallet found")
            return
        }
        
        BlockchainAPIClient.shared.getTransactionHistory(address: address) { [weak self] result in
            DispatchQueue.main.async {
                switch result {
                case .success(let transactions):
                    self?.showAlert(title: "Transaction History", message: "Found \(transactions.count) transactions")
                case .failure(let error):
                    self?.showAlert(title: "Error", message: "Failed to load history: \(error.localizedDescription)")
                }
            }
        }
    }
    
    @objc private func exportKeyTapped() {
        guard let privateKey = WalletManager.shared.exportPrivateKey() else {
            showAlert(title: "Error", message: "No wallet found")
            return
        }
        
        let alertController = UIAlertController(title: "Private Key", message: privateKey, preferredStyle: .alert)
        alertController.addAction(UIAlertAction(title: "Copy", style: .default) { _ in
            UIPasteboard.general.string = privateKey
        })
        alertController.addAction(UIAlertAction(title: "Close", style: .cancel))
        present(alertController, animated: true)
    }
    
    private func showAlert(title: String, message: String) {
        let alert = UIAlertController(title: title, message: message, preferredStyle: .alert)
        alert.addAction(UIAlertAction(title: "OK", style: .default))
        present(alert, animated: true)
    }
}

